#!/usr/bin/env node
import { McpServer } from "@modelcontextprotocol/server";
import { StdioServerTransport } from "@modelcontextprotocol/server/stdio";
import { z } from "zod";
import sql from "mssql";

// ─── Connection config ────────────────────────────────────────────────────────
const baseConfig: sql.config = {
  server: process.env.MSSQL_SERVER ?? "IBMDEMOS\\SQLEXPRESS",
  user: process.env.MSSQL_USER ?? "causer",
  password: process.env.MSSQL_PASSWORD ?? "P@ssw0rd123",
  options: {
    trustServerCertificate: true,
    instanceName: undefined, // resolved from server string
  },
};

async function getPool(database?: string): Promise<sql.ConnectionPool> {
  const config: sql.config = { ...baseConfig, database };
  const pool = await sql.connect(config);
  return pool;
}

// ─── MCP Server ───────────────────────────────────────────────────────────────
const server = new McpServer({ name: "mssql-mcp-server", version: "1.0.0" });

// ── Tool 1: list-databases ────────────────────────────────────────────────────
server.registerTool(
  "list-databases",
  {
    description:
      "List all user databases on the connected SQL Server instance.",
    inputSchema: z.object({}),
  },
  async () => {
    try {
      const pool = await getPool("master");
      const result = await pool.request().query(
        "SELECT name, database_id, state_desc, create_date " +
        "FROM sys.databases " +
        "WHERE name NOT IN ('master','tempdb','model','msdb') " +
        "ORDER BY name"
      );
      await pool.close();
      return {
        content: [
          {
            type: "text" as const,
            text: JSON.stringify(result.recordset, null, 2),
          },
        ],
      };
    } catch (err) {
      return {
        content: [
          {
            type: "text" as const,
            text: `Error: ${err instanceof Error ? err.message : String(err)}`,
          },
        ],
        isError: true,
      };
    }
  }
);

// ── Tool 2: list-tables-by-database-name ─────────────────────────────────────
server.registerTool(
  "list-tables-by-database-name",
  {
    description:
      "List all user tables (with schema and row count) in the specified database.",
    inputSchema: z.object({
      database: z.string().describe("Name of the database to inspect."),
    }),
  },
  async ({ database }) => {
    try {
      const pool = await getPool(database);
      const result = await pool.request().query(
        "SELECT " +
        "  TABLE_SCHEMA AS [schema], " +
        "  TABLE_NAME   AS [table], " +
        "  TABLE_TYPE   AS [type] " +
        "FROM INFORMATION_SCHEMA.TABLES " +
        "ORDER BY TABLE_SCHEMA, TABLE_NAME"
      );
      await pool.close();
      return {
        content: [
          {
            type: "text" as const,
            text: JSON.stringify(result.recordset, null, 2),
          },
        ],
      };
    } catch (err) {
      return {
        content: [
          {
            type: "text" as const,
            text: `Error: ${err instanceof Error ? err.message : String(err)}`,
          },
        ],
        isError: true,
      };
    }
  }
);

// ── Tool 3: execute-query ─────────────────────────────────────────────────────
server.registerTool(
  "execute-query",
  {
    description:
      "Execute a raw T-SQL SELECT query against a specified database and return the results.",
    inputSchema: z.object({
      database: z.string().describe("Name of the database to run the query against."),
      query: z.string().describe("T-SQL SELECT query to execute."),
    }),
  },
  async ({ database, query }) => {
    // Safety: only allow SELECT statements
    const trimmed = query.trimStart().toUpperCase();
    if (!trimmed.startsWith("SELECT") && !trimmed.startsWith("WITH")) {
      return {
        content: [
          {
            type: "text" as const,
            text: "Error: Only SELECT (or WITH…SELECT) queries are permitted.",
          },
        ],
        isError: true,
      };
    }
    try {
      const pool = await getPool(database);
      const result = await pool.request().query(query);
      await pool.close();
      return {
        content: [
          {
            type: "text" as const,
            text: JSON.stringify(
              { rowsAffected: result.rowsAffected, recordset: result.recordset },
              null,
              2
            ),
          },
        ],
      };
    } catch (err) {
      return {
        content: [
          {
            type: "text" as const,
            text: `Error: ${err instanceof Error ? err.message : String(err)}`,
          },
        ],
        isError: true,
      };
    }
  }
);

// ─── Entry point ─────────────────────────────────────────────────────────────
async function main() {
  const transport = new StdioServerTransport();
  await server.connect(transport);
  console.error("mssql-mcp-server running on stdio");
}

main().catch((err) => {
  console.error("Fatal error:", err);
  process.exit(1);
});

